            "description": "Here are some common questions we receive from our international patients.",
            "faqData": [
              {
                "id": 566,
                "question": "What are the costs?",
                "answer": "Costs vary based on the type of treatment and hospital. We provide transparent pricing and can help you understand all potential expenses. Contact us for a personalized estimate."
              },
              {
                "id": 567,
                "question": "How long will it take?",
                "answer": "Treatment duration depends on your specific condition and chosen procedure. Most patients stay 1-4 weeks including recovery time. We provide detailed timelines during consultation."
              },
              {
                "id": 568,
                "question": "What about language barriers?",
                "answer": "All our partner hospitals have English-speaking staff and translators. We also provide dedicated coordinators who speak your language to assist throughout your journey."
              },
              {
                "id": 569,
                "question": "Is it safe to travel for medical care?",
                "answer": "Saudi Arabia has world-class medical facilities with international accreditation. We work only with top-tier hospitals that meet the highest safety and quality standards."
              },
              {
                "id": 570,
                "question": "What support is available for family?",
                "answer": "We provide comprehensive family support including accommodation arrangements, local transportation, cultural orientation, and 24/7 assistance during your stay."
              }
            ]
